  digitalWrite(segC, c);
  digitalWrite(segD, d);
  digitalWrite(segE, e);
  digitalWrite(segF, f);
  digitalWrite(segG, g);
}

void loop() {
  int potValue = analogRead(potPin);
  int digit = map(potValue, 0, 1023, 0, 9);
  displayDigit(digit);
  delay(50);
}
